class Solution:
    def findAllPeople(self, n, meetings, firstPerson):
        know = [False] * n
        know[0] = True
        know[firstPerson] = True
        events = sorted(meetings, key=lambda m: m[2])
        i, m = 0, len(events)
        while i < m:
            t = events[i][2]
            j = i
            batch = []
            while j < m and events[j][2] == t:
                batch.append(events[j])
                j += 1
            changed = True
            while changed:
                changed = False
                for x, y, _ in batch:
                    if know[x] and not know[y]:
                        know[y] = True
                        changed = True
                    elif know[y] and not know[x]:
                        know[x] = True
                        changed = True
            i = j
        return [k for k in range(n) if know[k]]

