var findAllPeople = function(n, meetings, firstPerson) {
    const know = new Array(n).fill(false);
    know[0] = true;
    know[firstPerson] = true;

    const byTime = new Map();
    for (const [x, y, t] of meetings) {
        if (!byTime.has(t)) byTime.set(t, []);
        byTime.get(t).push([x, y]);
    }

    const times = Array.from(byTime.keys()).sort((a, b) => a - b);
    for (const t of times) {
        const edges = byTime.get(t);
        const parent = new Map();
        const find = (a) => {
            if (!parent.has(a)) parent.set(a, a);
            while (parent.get(a) !== a) {
                parent.set(a, parent.get(parent.get(a)));
                a = parent.get(a);
            }
            return a;
        };
        const union = (a, b) => {
            const ra = find(a), rb = find(b);
            if (ra !== rb) parent.set(ra, rb);
        };
        for (const [x, y] of edges) union(x, y);

        const groups = new Map();
        for (const node of parent.keys()) {
            const root = find(node);
            if (!groups.has(root)) groups.set(root, []);
            groups.get(root).push(node);
        }

        for (const members of groups.values()) {
            if (members.some(m => know[m])) {
                for (const m of members) know[m] = true;
            }
        }
    }

    const res = [];
    for (let i = 0; i < n; i++) if (know[i]) res.push(i);
    return res;
};
